import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge } from 'decantr/components';

code.example:
function BeforeAfterBrowserFrames() {
  const { section, div, span, h2, p } = tags;

  return section({ class: css('_py30 _relative _z1') },
    div({ class: css('_container') },
      h2({ class: css('_heading2 _text[center] _mb4') }, 'The Problem We Solve'),
      p({ class: css('_text[center] _fgmuted _mw[620px] _mx[auto] _mb14') }, 'AI-generated UIs drift. Every regeneration produces different spacing, colors, and layouts.'),
      div({ class: css('_grid _gc2 _gap12 _mw[920px] _mx[auto]') },
        // Without column
        div({},
          div({ class: css('_fs[0.85rem] _fw700 _uppercase _ls[0.08em] _mb4 _text[center] _fgcoral') }, 'Without Product'),
          // 3 browser frame cards with warm gradient showing drift
          Card({ class: css('_rounded[14px] _p5 _mb4'), style: 'background:linear-gradient(135deg,#F58882,#FE4474)' },
            div({ class: css('_flex _items[center] _gap1 _mb3') },
              span({ class: css('_w[7px] _h[7px] _rounded[50%] _bgwhite/40') }),
              span({ class: css('_w[7px] _h[7px] _rounded[50%] _bgwhite/40') }),
              span({ class: css('_w[7px] _h[7px] _rounded[50%] _bgwhite/40') })
            ),
            // Mock content blocks with varying sizes (showing inconsistency)
            div({ class: css('_rounded[6px] _h[16px] _mb2 _bgwhite/15'), style: 'width:70%' }),
            div({ class: css('_rounded[6px] _h[16px] _mb2 _bgwhite/15'), style: 'width:90%' })
          )
        ),
        // With column
        div({},
          div({ class: css('_fs[0.85rem] _fw700 _uppercase _ls[0.08em] _mb4 _text[center] _fggreen') }, 'With Product'),
          // 3 browser frame cards with cool gradient showing consistency
          Card({ class: css('_rounded[14px] _p5 _mb4'), style: 'background:linear-gradient(135deg,#0AF3EB,#00E0AB)' },
            div({ class: css('_flex _items[center] _gap1 _mb3') },
              span({ class: css('_w[7px] _h[7px] _rounded[50%] _bgdark/30') }),
              span({ class: css('_w[7px] _h[7px] _rounded[50%] _bgdark/30') }),
              span({ class: css('_w[7px] _h[7px] _rounded[50%] _bgdark/30') })
            ),
            // Uniform mock content blocks
            div({ class: css('_rounded[6px] _h[16px] _mb2 _bgdark/10'), style: 'width:80%' }),
            div({ class: css('_rounded[6px] _h[16px] _mb2 _bgdark/10'), style: 'width:80%' })
          ),
          Badge({ class: css('_inline _px4 _py1 _rounded[20px] _bggreen _fgdark _fs[0.72rem] _fw700 _uppercase _mt3') }, 'Zero Drift')
        )
      )
    )
  );
}

